<template>
<section>
    <div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div
                            class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">History</h5>
                          <button type="button" @click="closeHistory">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                        </div>
                <div class="modal-body">
 <tg-list :IsShowAction="false" ModuleName="RateSchedule" SubModuleCode="" :LegendArray="[]" :RenderRowActionMethod="renderActions" 
    v-on:ActionButtonClick="actionButtonClick" :widgets="[]" IdentityColumn="RATE_SCHEDULE_ID" :listType="['List']" :ListData="RateScheduleData" 
    :HeaderData="Headers" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" IsSearchFieldsOnTop="false" 
    :ListDataCallBackFunction="FetchData" :showCheckBox="false" :SortExp="SortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" 
    :HeaderText="$t('RateSchedule')" v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod" 
    v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">
        <template v-slot:slotdata="{ data }">
            <template v-if="data.column.COLUMN_NAME == 'START_DATE'">
                <span>
                    {{ $options.filters.formatDate(data.row.START_DATE) }}
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'END_DATE'">
                <span>
                    {{ $options.filters.formatDate(data.row.END_DATE) }}
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'CREATED_AT'">
                <span>
                    {{ $options.filters.formatDateTime(data.row.CREATED_AT) }}
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'MODIFIED_AT'">
                <span>
                    {{ $options.filters.formatDateTime(data.row.MODIFIED_AT) }}
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'STATUS_ID'">
                <span v-if="data.row.STATUS_ID==1001" class="px-2 text-center bg-success text-white d-block">{{ $t('Active') }}</span>
                <span v-else class="px-2 text-center bg-danger text-white d-block">{{ $t('InActive') }}</span>
            </template>          
        </template>
    </tg-list>    
                </div>
            </div>
        </div>
    </div>
</div>
   
</section>
</template>

<script>
import DataService from "../../../services/DataService";

export default {
    components: {},
     props: {
        ClientId: {
            type: Number,
            required: true,
        },
    },
    data() {
        return {
            isLoading: false,
            Headers: [{
                    "COLUMN_NAME": "CLIENT_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Contract',
                    "DISPLAY_ORDER": 1,
                    // settings: {
                    //     isInSlot: false
                    // }
                },
                {
                    "COLUMN_NAME": "WORK_CODE",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Work Code',
                    "DISPLAY_ORDER": 2,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "UTILITY_NAME",
                    "DATA_TYPE": "Date",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Utility Name',
                    "DISPLAY_ORDER": 3,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "STATE_NAME",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'State',
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: false
                    }
                },
                {
                    "COLUMN_NAME": "BILLING_CODE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Customer Work Code',
                    "DISPLAY_ORDER": 5,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "AMOUNT",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Rate',
                    "DISPLAY_ORDER": 6,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "STATUS_ID",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Status',
                    "DISPLAY_ORDER": 7,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "START_DATE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Start Date',
                    "DISPLAY_ORDER": 8,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "END_DATE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'End Date',
                    "DISPLAY_ORDER": 9,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "MODIFIED_BY",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Modified By',
                    "DISPLAY_ORDER": 12,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "MODIFIED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Modified Date',
                    "DISPLAY_ORDER": 13,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "COMMENT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'COMMENT',
                    "DISPLAY_ORDER": 13,
                    // settings: {
                    //     isInSlot: true
                    // }
                }
            ],
            SortBy: null,
            SortExp: null,
            PageSize: "10",
            PageNumber: "1",
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            noRecords: false,
            searchCondition: '',
            RateScheduleData: [],
            CompanyId: null,
            UserId: null,
            searchBy: '',
            search: '',
            //isBillingType: false,
        }
    },
    created: async function () {
       // debugger
        var vm = this;
         this.isBillingType = localStorage.getItem("billingType") === "USIC";
        vm.CompanyId = this.GetUserInfo.CompanyId;
        vm.UserId = this.GetUserInfo.ID;
          if (this.isBillingType) {
           await vm.FetchData();  
          }    
          
    },
    methods: {
    
     
        
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            debugger
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'Edit':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        FetchData: async function () {
            debugger
            var vm = this;
            var params = '';
            vm.isLoading = true;
                  var params = `pageSize=${vm.PageSize}&pageNum=1&sortBy=${vm.SortBy || ''}&sortExp=${vm.SortExp || ''}&clientId=${vm.ClientId}&Search=${vm.searchCondition || ''}&isBillingType=${vm.isBillingType}&clientIds=${vm.clientIds || ''}&workCodes=${vm.workCodes || ''}`;
            
            await DataService.ListHistoryRateSchedules(params).then((response) => {
                //debugger;
                if (response.data.result.length > 0) {
                    vm.isLoading = false;
                    vm.RateScheduleData = JSON.parse(response.data.result);
                    vm.TotalRecords = vm.RateScheduleData[0].TOTAL_RECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                    vm.noRecords = false;
                } else {
                    vm.RateScheduleData = [];
                    vm.noRecords = true;
                    vm.TotalRecords = 0
                    vm.isLoading = false;
                }
            })
        },
        closeHistory(){
             if (this.isBillingType) {
                debugger
            this.$parent.FetchData();
            this.$parent.isViewHistory = false;
            }
        }
    
    }
}
</script>
